import{_ as d,o as a,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"深化研究：电改 2.0 落地时间表——各省电力现货市场进展","description":"","frontmatter":{},"headers":[],"relativePath":"算电协同/_深化_2026-06-13_电改2.0落地时间表.md","filePath":"算电协同/_深化_2026-06-13_电改2.0落地时间表.md","lastUpdated":1781535932000}'),l={name:"算电协同/_深化_2026-06-13_电改2.0落地时间表.md"};function e(i,t,h,n,s,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="深化研究-电改-2-0-落地时间表——各省电力现货市场进展" tabindex="-1">深化研究：电改 2.0 落地时间表——各省电力现货市场进展 <a class="header-anchor" href="#深化研究-电改-2-0-落地时间表——各省电力现货市场进展" aria-label="Permalink to &quot;深化研究：电改 2.0 落地时间表——各省电力现货市场进展&quot;">​</a></h1><p><strong>日期：</strong> 2026-06-13 | <strong>来源：</strong> websearch + 政策原文 <strong>对应问题：</strong> 待深化问题 P0#3</p><hr><h2 id="一、核心结论" tabindex="-1">一、核心结论 <a class="header-anchor" href="#一、核心结论" aria-label="Permalink to &quot;一、核心结论&quot;">​</a></h2><p>2025年是全国统一电力市场的里程碑之年，2026年进入&quot;基本建成&quot;冲刺期。</p><p><strong>关键节点：</strong></p><ul><li>✅ 2025年底：电力现货市场实现<strong>基本全覆盖</strong></li><li>🎯 2026年：全国<strong>一半以上省份</strong>现货市场转入正式运行</li><li>🎯 2026年6月底：安徽、陕西力争转正</li><li>🎯 2026年Q4：南方区域市场可能转正</li></ul><hr><h2 id="二、政策框架时间线" tabindex="-1">二、政策框架时间线 <a class="header-anchor" href="#二、政策框架时间线" aria-label="Permalink to &quot;二、政策框架时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>政策/事件</th><th>意义</th></tr></thead><tbody><tr><td>2025年4月</td><td>发改委394号文《全面加快电力现货市场建设工作通知》</td><td>明确各省时间表，要求2025年底全覆盖</td></tr><tr><td>2025年12月</td><td>省级现货市场基本全覆盖</td><td>✅ 394号文目标达成</td></tr><tr><td>2026年5月</td><td>《2025年度中国电力市场发展报告》发布</td><td>明确2026年六大方向</td></tr><tr><td>2026年</td><td>&quot;十五五&quot;开局</td><td>统一市场从&quot;初步建成&quot;→&quot;基本建成&quot;</td></tr></tbody></table><hr><h2 id="三、各省现货市场进展一览-截至2026年6月" tabindex="-1">三、各省现货市场进展一览（截至2026年6月） <a class="header-anchor" href="#三、各省现货市场进展一览-截至2026年6月" aria-label="Permalink to &quot;三、各省现货市场进展一览（截至2026年6月）&quot;">​</a></h2><h3 id="✅-已正式运行-7省区" tabindex="-1">✅ 已正式运行（7省区） <a class="header-anchor" href="#✅-已正式运行-7省区" aria-label="Permalink to &quot;✅ 已正式运行（7省区）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>省份</th><th>转正时间</th><th>特点</th></tr></thead><tbody><tr><td>山西</td><td>2023年底</td><td>首批试点，运行最成熟</td></tr><tr><td>广东</td><td>2024年6月</td><td>负荷最大，电价最高（4月均价637.91元/MWh）</td></tr><tr><td>山东</td><td>2024年6月</td><td>新能源渗透率高，现货低价频现</td></tr><tr><td>甘肃</td><td>2024年9月</td><td>新能源占比最高，午间地板价常态化</td></tr><tr><td>蒙西</td><td>2025年2月</td><td>首个非试点转正</td></tr><tr><td>湖北</td><td>2025年6月</td><td>—</td></tr><tr><td>浙江</td><td>2025年底</td><td>—</td></tr></tbody></table><h3 id="🔄-连续结算试运行-即将转正" tabindex="-1">🔄 连续结算试运行（即将转正） <a class="header-anchor" href="#🔄-连续结算试运行-即将转正" aria-label="Permalink to &quot;🔄 连续结算试运行（即将转正）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>省份</th><th>启动时间</th><th>预计转正</th></tr></thead><tbody><tr><td>安徽</td><td>2024年</td><td><strong>2026年6月底前</strong></td></tr><tr><td>陕西</td><td>2024年</td><td><strong>2026年6月底前</strong></td></tr><tr><td>辽宁</td><td>2025年3月</td><td>2026年</td></tr><tr><td>河北南网</td><td>2025年3月</td><td>2026年</td></tr><tr><td>南方区域市场</td><td>2025年6月</td><td>2026年（首个跨省区域市场）</td></tr></tbody></table><h3 id="🔄-长周期结算试运行" tabindex="-1">🔄 长周期结算试运行 <a class="header-anchor" href="#🔄-长周期结算试运行" aria-label="Permalink to &quot;🔄 长周期结算试运行&quot;">​</a></h3><p>福建、四川、江苏、湖南、河南、宁夏、重庆、上海、吉林</p><h3 id="🔄-短周期结算试运行" tabindex="-1">🔄 短周期结算试运行 <a class="header-anchor" href="#🔄-短周期结算试运行" aria-label="Permalink to &quot;🔄 短周期结算试运行&quot;">​</a></h3><p>江西、黑龙江、新疆、蒙东、青海</p><hr><h2 id="四、2026年六大重点方向-官方" tabindex="-1">四、2026年六大重点方向（官方） <a class="header-anchor" href="#四、2026年六大重点方向-官方" aria-label="Permalink to &quot;四、2026年六大重点方向（官方）&quot;">​</a></h2><p>根据《2025年度中国电力市场发展报告》（2026年5月发布）：</p><ol><li><strong>过半省份现货市场正式运行</strong> — 南方区域及安徽、陕西、福建、辽宁、河北南网转正</li><li><strong>区域省间交易常态化</strong> — 西北、华中短期互济常态化</li><li><strong>零售市场秩序规范</strong> — 售电公司从&quot;价差套利&quot;→&quot;服务增值&quot;</li><li><strong>中长期交易质效提升</strong> — 逐步取消固定分时电价</li><li><strong>辅助服务加速</strong> — 爬坡、转动惯量等新品种</li><li><strong>数字化监管全覆盖</strong></li></ol><hr><h2 id="五、各省电价分化态势-2026年4月数据" tabindex="-1">五、各省电价分化态势（2026年4月数据） <a class="header-anchor" href="#五、各省电价分化态势-2026年4月数据" aria-label="Permalink to &quot;五、各省电价分化态势（2026年4月数据）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>省份</th><th>4月均价（元/MWh）</th><th>环比</th><th>特点</th></tr></thead><tbody><tr><td>广东</td><td><strong>637.91</strong></td><td>+64.80%</td><td>供需持续偏紧，全月高位</td></tr><tr><td>甘肃</td><td>145.12</td><td>-32.31%</td><td>新能源大发，午间地板价</td></tr><tr><td>辽宁</td><td>127.03</td><td>-47.41%</td><td>降幅最大</td></tr><tr><td>山西/山东</td><td>230-280</td><td>回落</td><td>时段性供需错配</td></tr></tbody></table><blockquote><p><strong>投资含义：</strong> 区域电价分化=套利机会。西部低价区（甘肃/蒙西/新疆）的算电协同项目在绿电成本上具有确定性优势。</p></blockquote><hr><h2 id="六、投资启示" tabindex="-1">六、投资启示 <a class="header-anchor" href="#六、投资启示" aria-label="Permalink to &quot;六、投资启示&quot;">​</a></h2><h3 id="对算电协同赛道的影响" tabindex="-1">对算电协同赛道的影响 <a class="header-anchor" href="#对算电协同赛道的影响" aria-label="Permalink to &quot;对算电协同赛道的影响&quot;">​</a></h3><ol><li><strong>电改加速→绿电直供政策窗口打开</strong> — 内蒙古已明确支持数据中心负荷开展绿电直连</li><li><strong>现货市场全覆盖→电价信号更灵敏</strong> — 数据中心需求响应的经济性增强</li><li><strong>辅助服务市场扩容→灵活性资源价值重估</strong> — 数据中心可压减负荷具备辅助服务资质</li><li><strong>京津冀电力市场建设→算力+电力跨区域协同</strong> — 乌兰察布→北京的低时延通道价值凸显</li></ol><h3 id="需要关注的风险点" tabindex="-1">需要关注的风险点 <a class="header-anchor" href="#需要关注的风险点" aria-label="Permalink to &quot;需要关注的风险点&quot;">​</a></h3><ul><li>各省现货规则差异大，实际落地仍有地方保护</li><li>容量电价政策尚未全国统一</li><li>绿电直供的输电通道占用费标准未明确</li><li>部分省份新能源入市后的补贴退坡节奏</li></ul><hr><h2 id="七、关键信息来源" tabindex="-1">七、关键信息来源 <a class="header-anchor" href="#七、关键信息来源" aria-label="Permalink to &quot;七、关键信息来源&quot;">​</a></h2><ul><li>发改委394号文（2025年4月）</li><li>《2025年度中国电力市场发展报告》（2026年5月）</li><li>各省2026年电力交易方案（29省已发布）</li><li>信达证券电改研报（2025年12月）</li><li>北极星电力市场网</li><li>数字储能网</li><li>RMI洞察报告《2025电力市场化改革与电价体系洞察》</li><li>2026年4月电力市场交易运行分析</li></ul>',37)])])}const _=d(l,[["render",e]]);export{c as __pageData,_ as default};
